    count = len(binary) // 50
    # Create valid Binary STL header
    header = b"BUILD123D_SIDEBUTTONARRAY_RECONSTRUCTION".ljust(80, b"\x00")
    payload = header + struct.pack("<I", count) + binary
    
    with open("temp_side.stl", "wb") as f_out: f_out.write(payload)
    part = import_stl("temp_side.stl")
    os.remove("temp_side.stl")
    
    # Save output STL in results folder
    output_dir = os.path.dirname(os.path.dirname(__file__))
